class Rectangle:
    def __init__(self, width, height):
        self.width = width
        self.height = height

    def area(self):
        return self.width * self.height

    def __str__(self):
        return f'Rectangle({self.width} x {self.height})'

class Square(Rectangle):
    def __init__(self, side):
        super().__init__(side, side)

def is_balanced(expression):
    stack = []
    matching = {')': '(', ']': '[', '}': '{'}
    for char in expression:
        if char in '([{':
            stack.append(char)
        elif char in ')]}':
            if not stack or stack[-1] != matching[char]:
                return False
            stack.pop()
    return len(stack) == 0

class FileProcessingError(Exception):
    def __init__(self, filename, message):
        self.filename = filename
        super().__init__(f'{filename}: {message}')

class FileFormatError(FileProcessingError):
    def __init__(self, filename, line_num, detail):
        self.line_num = line_num
        super().__init__(filename, f'format error on line {line_num}: {detail}')

class FileSizeError(FileProcessingError):
    def __init__(self, filename, size_mb, max_mb):
        self.size_mb = size_mb
        super().__init__(filename, f'file is {size_mb}MB, max is {max_mb}MB')

