public static Integer maxValue(int[] numbers) {
    if (numbers.length == 0) {
        return null;
    }
    int result = numbers[0];
    for (int i = 1; i < numbers.length; i++) {
        if (numbers[i] > result) {
            result = numbers[i];
        }
    }
    return result;
}

